#include <stdio.h>
#include <stdlib.h>


/*Izgled datoteke

Ilic Ana 45
Kovac Marko 38
Basic Sara 50

*/


struct Student {
    char prezime[20];
    char ime[15];
    int broj_bodova;
};

int main() {
    struct Student studenti[300];
    FILE *ulaz;
    int i, vel;

    /* otvaranje datoteke */
    ulaz = fopen("ispit.txt", "r");
    if (ulaz == NULL) {
        printf("Greska pri otvaranju datoteke ispit.txt\n");
        return 1;
    }

    /* ucitavanje datoteke u niz studenti */
    i = 0;
while (i < 300 &&
       fscanf(ulaz, "%19s %14s %d",
              studenti[i].prezime,
              studenti[i].ime,
              &studenti[i].broj_bodova) == 3) {
    i++;
}
vel = i;


    fclose(ulaz);

    /* ispis ucitanih podataka */
    if (vel == 0) {
        printf("Datoteka je prazna ili format nije ispravan.\n");
        return 0;
    }

    printf("Ucitano studenata: %d\n", vel);
    printf("-----------------------------------------\n");
    printf("%-20s %-15s %s\n", "Prezime", "Ime", "Bodovi");
    printf("-----------------------------------------\n");

    for (i = 0; i < vel; i++) {
        printf("%-20s %-15s %d\n",
               studenti[i].prezime,
               studenti[i].ime,
               studenti[i].broj_bodova);
    }

    return 0;
}
